classdef MultiHarmonicHeightCurve
    %MULTIHARMONICHEIGHTCURVE Exact-transport {1,2,4} height costs.
    %
    % Moving gradients are sampled at every warped patch point, transported
    % with the local real Jacobian, and only then raised to each harmonic.
    % Invalid support remains NaN and each single harmonic remains separate.
    % Traceability: algo/main.tex Secs. 7, 8.1-8.3, and Algorithm 1;
    % Eqs. (96)-(109), especially (98), (101), (103), and (106)-(108).

    properties (SetAccess = private)
        CostCurve
    end

    methods
        function obj = MultiHarmonicHeightCurve(costCurve)
            arguments
                costCurve (1, 1) HeightCostCurve
            end

            obj.CostCurve = costCurve;
        end

        function result = evaluate(obj, p, z, options)
            %EVALUATE Compute raw single/fixed/adaptive harmonic curves.

            arguments
                obj (1, 1) MultiHarmonicHeightCurve
                p (:, 2) double {mustBeFinite, mustBeNonempty}
                z (1, :) double {mustBeFinite, mustBeNonempty}
                options.DeltaPixel (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
                options.MinimumGradient (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-6
                options.EpsilonGradient (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1e-6
                options.RequireOrientationPreserving (1, 1) logical = true
                options.FixedWeights (1, 3) double ...
                    {mustBeFinite, mustBeNonnegative, ...
                    mustHavePositiveSum} = [1, 1, 1]
                options.PolarityPreservedProbability (:, 1) double ...
                    {mustBeFinite, mustBeProbability, ...
                    mustHaveOneOrNRows( ...
                    options.PolarityPreservedProbability, p)} = 1
                options.OrthogonalStructureProbability (:, 1) double ...
                    {mustBeFinite, mustBeProbability, ...
                    mustHaveOneOrNRows( ...
                    options.OrthogonalStructureProbability, p)} = 1
                options.LowAngularNoiseProbability (:, 1) double ...
                    {mustBeFinite, mustBeProbability, ...
                    mustHaveOneOrNRows( ...
                    options.LowAngularNoiseProbability, p)} = 1
                options.MinimumAdaptiveWeightSum (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1e-6
                options.RetainDiagnostics (1, 1) logical = true
            end

            orders = [1, 2, 4];
            reference = obj.CostCurve.Reference;
            moving = obj.CostCurve.Moving;
            geometry = obj.CostCurve.Geometry;
            [ox, oy] = meshgrid( ...
                -reference.IntegrationRadius:reference.IntegrationRadius);
            off = [ox(:), oy(:)];
            n = size(p, 1);
            np = size(off, 1);
            nl = numel(z);
            pp = reshape(p, n, 1, 2) + reshape(off, 1, np, 2);
            pp = reshape(pp, n .* np, 2);
            kw = reference.IntegrationKernel(:).';

            [gr, vgr] = reference.sampleGradient(pp);
            gr = reshape(gr, n, np);
            vgr = reshape(vgr, n, np) ...
                & abs(gr) >= options.MinimumGradient;
            [qr, ~, vr, referenceSupport] = ...
                MultiHarmonicHeightCurve.descriptor( ...
                gr, vgr, kw, orders, options.MinimumSupportFraction, ...
                options.EpsilonGradient, reference.Epsilon);

            single = nan(n, nl, 3);
            fixed = nan(n, nl);
            adaptive = nan(n, nl);
            if options.RetainDiagnostics
                pairedConfidence = nan(n, nl, 3);
                adaptiveWeights = nan(n, nl, 3);
                chi12 = nan(n, nl);
                chi24 = nan(n, nl);
            else
                pairedConfidence = nan(n, 0, 3);
                adaptiveWeights = nan(n, 0, 3);
                chi12 = nan(n, 0);
                chi24 = nan(n, 0);
            end
            support = zeros(n, nl);
            for k = 1:nl
                [w, vw] = geometry.warp(pp, z(k));
                [gm, vgm] = moving.sampleGradient(w);
                [a, va] = geometry.warpJacobian( ...
                    pp, z(k), DeltaPixel=options.DeltaPixel);
                ht = ComplexGradientImage.transport(gm, a);
                detA = a(:, 1, 1) .* a(:, 2, 2) ...
                    - a(:, 1, 2) .* a(:, 2, 1);
                orientationValid = ~options.RequireOrientationPreserving ...
                    | detA > 0;
                ht = reshape(ht, n, np);
                vht = reshape( ...
                    vgm & vw & va & orientationValid, n, np) ...
                    & abs(ht) >= options.MinimumGradient;
                [qm, ~, vm, movingSupport] = ...
                    MultiHarmonicHeightCurve.descriptor( ...
                    ht, vht, kw, orders, ...
                    options.MinimumSupportFraction, ...
                    options.EpsilonGradient, reference.Epsilon);
                qrPair = qr;
                qmPair = qm;
                pairValid = vr & vm;
                qrPair(~pairValid) = NaN;
                qmPair(~pairValid) = NaN;
                fusion = MultiHarmonicFusion.fuse(qrPair, qmPair, ...
                    FixedWeights=options.FixedWeights, ...
                    PolarityPreservedProbability= ...
                    options.PolarityPreservedProbability, ...
                    OrthogonalStructureProbability= ...
                    options.OrthogonalStructureProbability, ...
                    LowAngularNoiseProbability= ...
                    options.LowAngularNoiseProbability, ...
                    Epsilon=reference.Epsilon, ...
                    MinimumAdaptiveWeightSum= ...
                    options.MinimumAdaptiveWeightSum);
                single(:, k, :) = fusion.PerHarmonicCost;
                fixed(:, k) = fusion.FixedCost;
                adaptive(:, k) = fusion.AdaptiveCost;
                if options.RetainDiagnostics
                    pairedConfidence(:, k, :) = fusion.PairedConfidence;
                    adaptiveWeights(:, k, :) = fusion.AdaptiveWeights;
                    chi12(:, k) = fusion.Chi12;
                    chi24(:, k) = fusion.Chi24;
                end
                support(:, k) = min(referenceSupport, movingSupport);
            end

            costs = struct( ...
                "Harmonic1", single(:, :, 1), ...
                "Harmonic2", single(:, :, 2), ...
                "Harmonic4", single(:, :, 3), ...
                "Fixed124", fixed, ...
                "Adaptive124", adaptive);
            supportFraction = struct( ...
                "Harmonic1", support, "Harmonic2", support, ...
                "Harmonic4", support, "Fixed124", support, ...
                "Adaptive124", support);
            selected = struct;
            valid = struct;
            names = fieldnames(costs);
            for k = 1:numel(names)
                selected.(names{k}) = ...
                    MultiHarmonicHeightCurve.selectHeight( ...
                    costs.(names{k}), z);
                valid.(names{k}) = isfinite(costs.(names{k}));
            end
            result = struct( ...
                "ReferencePixel", p, ...
                "Height", z, ...
                "Costs", costs, ...
                "SelectedHeight", selected, ...
                "Valid", valid, ...
                "SupportFraction", supportFraction, ...
                "ReferenceDescriptor", qr, ...
                "ReferenceDescriptorValid", vr, ...
                "PairedConfidence", pairedConfidence, ...
                "AdaptiveWeights", adaptiveWeights, ...
                "Chi12", chi12, "Chi24", chi24, ...
                "DiagnosticsRetained", options.RetainDiagnostics, ...
                "HarmonicOrders", orders, ...
                "FixedWeights", options.FixedWeights ...
                ./ sum(options.FixedWeights), ...
                "PolarityPreservedProbability", ...
                options.PolarityPreservedProbability, ...
                "OrthogonalStructureProbability", ...
                options.OrthogonalStructureProbability, ...
                "LowAngularNoiseProbability", ...
                options.LowAngularNoiseProbability, ...
                "Regularization", "none", ...
                "Transport", "pointwise real-Jacobian before powers", ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", "local ENU metres", ...
                "ElevationDatum", "local synthetic ENU Z=0");
        end
    end

    methods (Static, Access = private)
        function [q, c, valid, support] = descriptor( ...
                g, validSample, kw, orders, minSupport, epsilonGradient, ...
                epsilonDescriptor)
            % Eq. (98): energy-weighted circular Fourier coefficients.
            w = double(validSample) .* kw;
            support = sum(w, 2);
            gg = g;
            gg(~validSample) = 0;
            r2 = abs(gg) .^ 2;
            u = gg ./ sqrt(r2 + epsilonGradient ^ 2);
            eta = r2 .* double(validSample);
            evidence = sum(w .* eta, 2);
            d = evidence + epsilonDescriptor;
            q = complex(zeros(size(g, 1), numel(orders)));
            for k = 1:numel(orders)
                q(:, k) = sum(w .* eta .* u .^ orders(k), 2) ./ d;
            end
            valid = repmat( ...
                support >= minSupport & evidence > epsilonDescriptor, ...
                1, numel(orders));
            q(~valid) = NaN;
            c = abs(q);
        end

        function selected = selectHeight(cost, z)
            [~, k] = min(cost, [], 2, "omitnan");
            selected = reshape(z(k), [], 1);
            selected(all(isnan(cost), 2)) = NaN;
        end
    end
end

function mustHaveOneOrNRows(a, p)
if ~(size(a, 1) == 1 || size(a, 1) == size(p, 1))
    error("MultiHarmonicHeightCurve:RowCountMismatch", ...
        "Each gate must have one row or one row per reference point.");
end
end

function mustBeProbability(x)
if any(x < 0 | x > 1, "all")
    error("MultiHarmonicHeightCurve:InvalidProbability", ...
        "Gate probabilities must lie in [0,1].");
end
end

function mustHavePositiveSum(x)
if sum(x) <= 0
    error("MultiHarmonicHeightCurve:ZeroWeightSum", ...
        "At least one fixed harmonic weight must be positive.");
end
end
